  function renderShell(){const page=element('div');page.append(skipLink(),demoBanner());const shell=element('div','app-shell');shell.append(topbar(),sidebar());const main=element('main','main-content');main.id='main-content';main.tabIndex=-1;main.append(state.currentView==='dashboard'?dashboardView():moduleView());shell.append(main);page.append(shell);replace(page)}
  async function loadDashboard(){state.dashboard=await api('/api/dashboard')}
  async function loadModule(key){state.moduleLoading=true;state.moduleError='';renderShell();try{if(key==='catalog')state.modules.catalog=await api('/api/catalog/products');if(key==='prices'){const [lists,prices]=await Promise.all([api('/api/price-lists'),api('/api/prices')]);state.modules.prices={...lists,...prices}}if(key==='inventory')state.modules.inventory=await api('/api/inventory');if(key==='customers')state.modules.customers=await api('/api/customers');if(['companies','company'].includes(key))state.modules[key]=await api('/api/companies');if(key==='requests')state.modules.requests=await api('/api/requests');if(key==='messages')state.modules.messages=await api('/api/conversations');if(key==='quotes')state.modules.quotes=await api('/api/quotes');if(key==='orders')state.modules.orders=await api('/api/orders');if(key==='notifications')state.modules.notifications=await api('/api/notifications');if(key==='audit')state.modules.audit=await api('/api/audit');if(key==='settings')state.modules.settings=await api('/api/settings');if(key==='reports')state.modules.reports=await api('/api/reports');if(key==='account'){const [sessions,mfa]=await Promise.all([api('/api/account/sessions'),api('/api/account/mfa')]);state.modules.account={...sessions,mfa}};if(key==='inbox')state.modules.inbox=await api('/api/inbox');if(key==='documents')state.modules.documents=await api('/api/documents');if(key==='returns'){const [returns,orders]=await Promise.all([api('/api/returns'),api('/api/orders')]);state.modules.returns={...returns,orders}}if(key==='advanced'){const [diagnostics,teams,jobs,deliveryData]=await Promise.all([api('/api/admin/diagnostics'),api('/api/teams'),api('/api/admin/jobs'),api('/api/deliveries')]);state.modules.advanced={diagnostics,teams:teams.teams,jobs:jobs.jobs,deliveries:deliveryData.deliveries}}}catch(failure){state.moduleError=failure.message}finally{state.moduleLoading=false;renderShell()}}
  async function openView(key){state.currentView=key;state.menuOpen=false;state.moduleMessage='';state.moduleError='';state.customerEdit=null;renderShell();if(['catalog','prices','inventory','customers','companies','company','requests','messages','quotes','orders','notifications','audit','settings','reports','account','inbox','documents','returns','advanced'].includes(key))await loadModule(key);document.getElementById('main-content')?.focus()}
  async function logout(){try{await api('/api/auth/logout',{method:'POST'})}catch(failure){console.warn('Logout local:',failure.message)}resetSessionState();loginView()}
